text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "topic": "공개 रिलीज 타깃",
        "decision": "스모크 테스트가 통과하면 공개 रिलीज 타깃은 금요일 15:00 KST로 तय했다."
      },
      {
        "topic": "packageName 불일치 처리",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 재검토하기로 했다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일 रिलीज",
        "reason": "스모크 테스트 통과가 선행되어야 한다는 반대가 있어 채택되지 않았다."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경",
        "reason": "합의 결과, 스크립트 변경보다 package config와 계약 적합성 확인을 우선하기로 하여 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 रिलीज",
        "status": "내부 스트레치 목표로만 언급됨"
      },
      {
        "goal": "README install steps 검토를 목요일까지 진행",
        "status": "가능하면 검토하자는 수준으로만 언급되었고 확정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path",
        "impact": "릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README install steps가 오래됨",
        "impact": "릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 release approval 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps 검토",
        "note": "Seoyeon이 가능하면 목요일 검토를 언급했지만 owner는 배정되지 않았다."
      },
      {
        "item": "Hara의 tarball path 확인",
        "note": "Minjun의 스모크 결과 이후 확인하기로 했지만 정확한 마감은 정해지지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과가 올라오면 generated tarball path를 확인한다.",
      "due": null,
      "status": "pending",
      "source_certainty": "명시됨"
    }
  ],
  "followup_note": "다음 확인 대상은 1) Minjun의 스모크 테스트 결과, 2) generated tarball path의 정확성, 3) README install steps의 최신성, 4) 최종 release approval 권한이다. 여기서 invent 하면 안 되는 항목은 고객명, 예산, 보안 사고, 프로덕션 장애, 법무 승인, 추가 owner, 추가 deadline이다.",
  "non_invention_rules": [
    "고객명이나 외부 파트너 이름은 넣지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항은 추가하지 않는다.",
    "명시되지 않은 owner, due date, approval authority를 추정하지 않는다.",
    "Friday 15:00 KST, Friday 10:00 KST, Friday 12:00 KST 외의 마감은 만들지 않는다.",
    "Wednesday는 내부 스트레치 목표로만 취급하고 확정 रिलीज로 쓰지 않는다.",
    "tarball path의 실제 값은 제공되지 않았으므로 추정하지 않는다."
  ]
}
